mapper.select:
SELECT aus.ai_us_regno as aiUsRegNo, aus.user_company_code as userCompanyCode, aus.dm_code as dmCode, aus.email as email, aus.session as session, aus.session_name as sessionName, aus.reg_ymd as regYmd, aus.status as status FROM AI_USER_SESSION aus WHERE status = 1
AND email = #{email}
AND email is NULL

mapper.delete:
UPDATE AI_USER_SESSION SET
status = 0
WHERE ai_us_regno = #{aiUsRegNo}

mapper.update:
UPDATE AI_USER_SESSION SET
    session_name = #{sessionName}
WHERE ai_us_regno = #{aiUsRegNo}
